import React, { useState } from "react";
import Sidebar from "./components/Sidebar";
import LoginBox from "./components/LoginBox";
import TaskModal from "./components/TaskModal";  // Import Add Project modal
import { FaProjectDiagram } from "react-icons/fa";
import { motion } from "framer-motion";

const AppLayout = () => {
  const [projects, setProjects] = useState([]);
  const [showLogin, setShowLogin] = useState(false);
  const [showAddProject, setShowAddProject] = useState(false);  // State for Add Project popup

  const addProject = (newProject) => {
    setProjects([...projects, newProject]);
    console.log("Project added:", newProject);
  };

  return (
    <div className="flex flex-col min-h-screen bg-gray-100">
      <div className="flex flex-grow">
        {/* Sidebar */}
        <aside className="w-50 bg-gray-900 text-white p-4">
          <Sidebar projects={projects} addProject={addProject} />
        </aside>

        {/* Main Content */}
        <main className="flex-1 flex flex-col items-center justify-center relative">
          <header className="bg-gradient-to-r from-purple-700 to-indigo-800 text-white py-4 px-6 shadow-lg w-full text-center">

            {/* Centered Icon Animation */}
            <div className="flex justify-center">
              <motion.div 
                animate={{ y: [0, -10, 0] }} // Move up & down
                transition={{ repeat: Infinity, duration: 1, ease: "easeInOut" }}
                className="flex items-center justify-center"
              >
                <FaProjectDiagram className="text-4xl text-yellow-300 mb-2" />
              </motion.div>
            </div>

            <h1 className="text-xl font-semibold">🚀 Manage Your Projects Efficiently With</h1>
            <h2 className="text-3xl font-extrabold text-yellow-300 mt-1">Proma</h2>
          </header>

          {/* Center Content - Welcome Section */}
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
            className="mt-10 bg-white shadow-lg rounded-xl p-6 w-3/4 text-center"
          >
            <h2 className="text-2xl font-bold text-gray-800">🚀 Welcome to <span className="text-indigo-600">Proma</span>!</h2>
            <p className="text-gray-600 mt-2">
              Manage your projects efficiently with ease. Start by adding your first project!
            </p>
            <button 
              onClick={() => setShowAddProject(true)}  // Open Add Project popup
              className="mt-4 px-5 py-2 bg-indigo-600 text-white rounded-lg font-semibold hover:bg-indigo-700 transition"
            >
              ➕ Add Project
            </button>
          </motion.div>

          {/* Login Button */}
          <button
            onClick={() => setShowLogin(!showLogin)}
            className="mt-4 bg-yellow-400 text-black px-4 py-2 rounded-lg font-semibold hover:bg-yellow-500 transition"
          >
            Login
          </button>

          {/* Login Box Popup */}
          {showLogin && (
            <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
              <motion.div
                initial={{ scale: 0.8, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                transition={{ duration: 0.3 }}
                className="bg-white p-6 rounded-xl shadow-2xl w-96 h-auto flex flex-col items-center relative"
              >
                <button
                  onClick={() => setShowLogin(false)}
                  className="absolute top-2 right-3 text-gray-700 hover:text-gray-900 text-xl"
                >
                  ✖
                </button>

                <LoginBox />
              </motion.div>
            </div>
          )}

          {/* Add Project Popup */}
          {showAddProject && (
            <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-50">
              <motion.div
                initial={{ scale: 0.8, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                transition={{ duration: 0.3 }}
                className="bg-white p-6 rounded-xl shadow-2xl w-96 h-auto flex flex-col items-center relative"
              >
                <button
                  onClick={() => setShowAddProject(false)}
                  className="absolute top-2 right-3 text-gray-700 hover:text-gray-900 text-xl"
                >
                  ✖
                </button>

                <TaskModal addProject={addProject} /> {/* Add Project Form */}
              </motion.div>
            </div>
          )}
        </main>
      </div>

      {/* Full-Width Footer */}
      <footer className="bg-gradient-to-r from-indigo-900 to-purple-900 text-gray-200 py-6 w-full text-center shadow-lg">
        <p className="text-md font-semibold tracking-wide">📞 Contact Us</p>
        <a href="mailto:support@example.com" className="text-red hover:text-yellow-400 transition">
          📧 support@example.com
        </a>
        <p className="text-sm mt-2 font-semibold">Follow Us:</p>
        <div className="flex justify-center space-x-3 mt-1">
          <a href="https://www.linkedin.com" className="hover:text-yellow">🔗 LinkedIn</a>
          <a href="https://www.facebook.com" className="hover:text-yellow">📘 Facebook</a>
          <a href="https://twitter.com" className="hover:text-yellow">🐦 Twitter</a>
        </div>
      </footer>
    </div>
  );
};

export default AppLayout;
